                            <input type="text" name="seconds_to_wait" class="form-control seconds_to_wait" value="{{!empty($script_detail) ? $script_detail->seconds_to_wait : ''}}">                                    </div>                                    <div class="form-group">                                        <label for="end_to_reset">{{lang('end_to_reset')}}</label>                                        <input type="text" name="end_to_reset" class="form-control end_to_reset" value="{{!empty($script_detail) ? $script_detail->end_to_reset : ''}}">                                    </div>                                </div>                                <div class="div_type_send">                                    <div class="form-group">                                        <label for="type_send">{{lang('c_send_message_with_role')}}</label>                                        <select class="type_send event_show select2" id="type_send"                                                data-placeholder="Chọn ..." name="type_send">                                            @if(!empty($type_send))                                                @foreach($type_send as $key => $value)                                                    <option value="{{$value['id']}}"                                                        {{$script_detail->type_send == $value['id'] ? 'selected' : ''}}>{{$value['name']}}</option>                                                @endforeach                                            @endif                                        </select>                                    </div>                                </div>                                <div class="checkbox checkbox-custom checkbox-inline m-t-10">                                    <input type="checkbox" class="active_start" data-check="active_start" id="active_start" name="active_start" {{!empty($script_detail->active_start) ? 'checked' : ''}} value="1">                                    <label for="active_start">{{lang('step_active_start')}}</label>                                </div>                                <div class="checkbox checkbox-custom checkbox-inline m-t-10">                                    <input type="checkbox" class="end_to_web" data-check="end_to_web" id="end_to_web" name="end_to_web" {{!empty($script_detail->end_to_web) ? 'checked' : ''}} value="1">                                    <label for="end_to_web">{{lang('packbot_end_to_web')}}</label>                                </div>                            </div>                            <div class="col-md-4 hide">                                <div id="img_review" class="text-center" style="border: 1px solid black;min-height: 100px;">                                    <?php if (!empty($script_detail->file)) { ?>                                        <?php $type_file = mime_content_type('storage/'.$script_detail->file); ?>                                        <?php if (explode('/', $type_file)[0] == 'video') { ?>                                            <video width="200px" height="auto" controls>                                                <source src="{{asset('storage/'.$script_detail->file)}}">                                            </video>                                        <?php } else if (explode('/', $type_file)[0] == 'image') { ?>                                            <img width="200px" height="auto" style="max-width: 400px!important;" src="{{asset('storage/'.$script_detail->file)}}"/>                                        <?php } ?>                                    <?php } ?>                                </div>                            </div>                        </div>                    </div>                </div>                <div class="clearfix"></div>                <div class="modal-footer mtop10">                    <button type="button" class="btn btn-default" data-dismiss="modal">{{lang('dt_close')}}</button>                    <button type="submit" class="btn btn-info">{{lang('dt_save')}}</button>                </div>            </div>        </form>    </div><script>    $('#form-edit_detail_child').find('select.select2').select2({clearSearch: true, width: '100%'});    $("#form-edit_detail_child").validate({        rules: {},        messages: {},        submitHandler: function (form) {            var url = form.action;            var form = $(form),                formData = new FormData(),                formParams = form.serializeArray();            $.each(form.find('input[type="file"]'), function (i, tag) {                $.each($(tag)[0].files, function (i, file) {                    formData.append(tag.name, file);                });            });            $.each(formParams, function (i, val) {                formData.append(val.name, val.value);            });            $.ajax({                url: url,                type: 'POST',                dataType: 'JSON',                cache: false,                contentType: false,                processData: false,                data: formData,            }).done(function (response) {                if (response.success == true) {                    $(`.div_child_${response.id}`).removeClass('active_view_app_0');                    $(`.div_child_${response.id}`).addClass(`active_view_app_${response.active_view_app}`);                    $(`.div_child_${response.id}`).html(response.html)                    alert_float('success', response.message);                    $.each(response.list_id, function(index, value) {                        if(response.active_view_app == 1) {                            $(`#c_active_${value}}`).attr('checked', true);                            $(`#c_active_${value}`).prop('checked', true);                        }                        else {                            $(`#c_active_${value}`).attr('checked', false);                            $(`#c_active_${value}`).prop('checked', false);                        }                    })                }                $('#dtModal').modal('hide');            })            .fail(function (err) {                htmlError = '';                for (var [ el, message ] of Object.entries(err.responseJSON.errors)) {                    htmlError += `<div>${message}</div>`;                }                $(".show_error").html(htmlError);                alert_float('error',htmlError);            });            return false;        }    });    $('#event_app').change(function() {        var type = $(this).val();        $.ajax({            url: 'admin/script/get_id_event_app',            type: 'GET',            dataType: 'JSON',            data: {type: type},        }).done(function (response) {            html = '<option></option>';            if(response) {                $.each(response, function(index, value) {                    html += `<option value="${value.id}">${value.name}</option>`;                });            }            $('#id_event_app').html(html).selectpicker('refresh');        })    })    $(function () {        $('input[name="file"]').change(function (e) {            var type = $('input[name="file"]').prop('files')[0].type.split('/')[0];            if(type == 'image') {                $('#img_review').html('<img style="width: 200px;height: auto" class="img_reiveIMG" src=""/>');                readURL(e.target, '.img_reiveIMG');            }            else if(type == 'video'){                $('#img_review').html(`<video autoplay width="200px" height="auto" controls>                                            <source class="img_reiveIMG" src="" type="video/mp4">                                      </video>`);                readURL(e.target, '.img_reiveIMG');            }        })        function readURL(input, thisData) {            if (input.files && input.files[0]) {                var reader = new FileReader();                reader.onload = function (e) {                    $(thisData).attr('src', e.target.result);                }                reader.readAsDataURL(input.files[0]);            }        }        $('#event_show').change(function() {            $('.event_button').addClass('hide');            $('.event_link').addClass('hide');            $('.event_helpdesk').addClass('hide');            $('.event_galary').addClass('hide');            $('.event_settimeout').addClass('hide');            $('.div_type_send').removeClass('hide');            if($(this).val() == 'button' || $(this).val() == 'options') {                $('.event_button').removeClass('hide');            }            if($(this).val() == 'link' || $(this).val() == 'youtube' || $(this).val() == 'video_youtube') {                $('.event_link').removeClass('hide');            }            if($(this).val() == 'galary') {                $('.event_galary').removeClass('hide');            }            if($(this).val() == 'settimeout') {                $('.event_settimeout').removeClass('hide');            }            if($(this).val() == 'content_center') {                $('.div_type_send').addClass('hide');            }            if($(this).val() == 'event_app') {                $('.div_event_app').removeClass('hide');            }        })    })    </script></div>